#include "controller.h"

/* Helper to check if sensors are stale */
static bool controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    /* Check turbidity freshness */
    if (controller->has_valid_turbidity && 
        ((now_ms < controller->last_turbidity_ms) || 
         (now_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS))) {
        return true;
    }

    /* Check level freshness */
    if (controller->has_valid_level && 
        ((now_ms < controller->last_level_ms) || 
         (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS))) {
        return true;
    }

    return false;
}

/* Set to safe idle state */
static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

/* Set filter ON, drain CLOSED (FILTERING state) */
static void controller_set_filtering(controller_t *controller)
{
    controller->filter_on = true;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_FILTERING;
}

/* Set filter OFF, drain CLOSED (SETTLING or DRAINING state) */
static void controller_set_settling(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->settling_started_ms = now_ms;
}

/* Set filter OFF, drain OPEN (DRAINING state) */
static void controller_set_draining(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = true;
    controller->state = CONTROLLER_STATE_DRAINING;
}

/* Set filter OFF, drain CLOSED (COMPLETE state) */
static void controller_set_complete(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_COMPLETE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Handle explicit timeout/invalid input - reset everything */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        output.timed_out = true;
    } else if (input.kind == CONTROLLER_INPUT_TURBIDITY || input.kind == CONTROLLER_INPUT_LEVEL) {
        /* Update sensor data based on input type */
        uint32_t now_ms = input.now_ms;

        if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = input.turbidity_ntu;
            controller->last_turbidity_ms = now_ms;
        } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
            controller->has_valid_level = true;
            controller->last_level = input.level;
            controller->last_level_ms = now_ms;
        }

        /* Check for sensor timeout before processing */
        if (controller_check_sensor_timeout(controller, now_ms)) {
            controller->has_valid_turbidity = false;
            controller->has_valid_level = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_safe_idle(controller);
            output.timed_out = true;
        } else if (!controller->has_valid_turbidity || !controller->has_valid_level) {
            /* Stay in safe idle until both sensors have been seen validly */
            controller_set_safe_idle(controller);
        } else {
            /* Both sensors are valid, run the state machine */
            int turb = controller->last_turbidity_ntu;
            int level = controller->last_level;

            switch (controller->state) {
                case CONTROLLER_STATE_SAFE_IDLE:
                    /* Check if we should transition to COMPLETE or FILTERING */
                    if (level < CONTROLLER_COMPLETE_LEVEL) {
                        controller_set_complete(controller);
                    } else if (turb > CONTROLLER_CLEAR_THRESHOLD_NTU && level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                        controller->clear_streak_count = 0;
                        controller_set_filtering(controller);
                    } else {
                        /* Stay in safe idle - waiting for conditions */
                        controller_set_safe_idle(controller);
                    }
                    break;

                case CONTROLLER_STATE_FILTERING:
                    /* Check for timeout or level drop */
                    if (level < CONTROLLER_COMPLETE_LEVEL) {
                        controller_set_complete(controller);
                    } else if (level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                        /* Update clear streak based on turbidity */
                        if (turb > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                            controller->clear_streak_count = 0;
                            controller_set_filtering(controller);
                        } else {
                            /* Clear sample - increment streak */
                            controller->clear_streak_count++;
                            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                                /* Transition to SETTLING */
                                controller_set_settling(controller, now_ms);
                            } else {
                                controller_set_filtering(controller);
                            }
                        }
                    } else {
                        /* Level too low for processing but not complete - go safe */
                        controller_set_safe_idle(controller);
                    }
                    break;

                case CONTROLLER_STATE_SETTLING:
                    /* Check for timeout or level drop */
                    if (level < CONTROLLER_COMPLETE_LEVEL) {
                        controller_set_complete(controller);
                    } else if (turb > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                        /* Disturbance during settling - return to FILTERING */
                        controller->clear_streak_count = 0;
                        controller_set_filtering(controller);
                    } else {
                        /* Check if settling period has elapsed and we can drain */
                        uint32_t settling_elapsed = now_ms - controller->settling_started_ms;
                        if (settling_elapsed >= CONTROLLER_SETTLING_MS && 
                            turb <= CONTROLLER_CLEAR_THRESHOLD_NTU && 
                            level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                            /* Transition to DRAINING */
                            controller_set_draining(controller);
                        } else {
                            /* Still settling */
                            controller->filter_on = false;
                            controller->drain_open = false;
                            controller->state = CONTROLLER_STATE_SETTLING;
                        }
                    }
                    break;

                case CONTROLLER_STATE_DRAINING:
                    /* Check for timeout or level drop */
                    if (level < CONTROLLER_COMPLETE_LEVEL) {
                        controller_set_complete(controller);
                    } else if (turb > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU && 
                               level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                        /* Disturbance during draining - close drain, restart filtering */
                        controller->clear_streak_count = 0;
                        controller_set_filtering(controller);
                    } else if (level < CONTROLLER_MIN_PROCESS_LEVEL) {
                        /* Level dropped below processing threshold but still >= complete level */
                        controller_set_complete(controller);
                    } else {
                        /* Continue draining */
                        controller_set_draining(controller);
                    }
                    break;

                case CONTROLLER_STATE_COMPLETE:
                    if (level < CONTROLLER_COMPLETE_LEVEL) {
                        controller_set_complete(controller);
                    } else {
                        /* Level rose above complete threshold - go back to safe idle or filtering */
                        if (turb > CONTROLLER_CLEAR_THRESHOLD_NTU && level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                            controller->clear_streak_count = 0;
                            controller_set_filtering(controller);
                        } else {
                            controller_set_safe_idle(controller);
                        }
                    }
                    break;

                default:
                    controller_set_safe_idle(controller);
                    break;
            }
        }
    } else {
        /* CONTROLLER_INPUT_NONE or unknown - check timeout */
        uint32_t now_ms = input.now_ms;
        if (controller_check_sensor_timeout(controller, now_ms)) {
            controller->has_valid_turbidity = false;
            controller->has_valid_level = false;
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_safe_idle(controller);
            output.timed_out = true;
        } else {
            /* No new input, maintain current state */
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            return output;
        }
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
